@SpringBootTest
@AutoConfigureMockMvc
class SecurityTests {

    @Autowired MockMvc mockMvc;

    @Test
    void admin_anonymous_shouldBeDenied() throws Exception {
        mockMvc.perform(get("/admin/panel"))
            .andExpect(status().isUnauthorized());
    }

    @Test
    @WithMockUser(username = "u", roles = {"USER"})
    void admin_userRole_shouldBeForbidden() throws Exception {
        mockMvc.perform(get("/admin/panel"))
            .andExpect(status().isForbidden());
    }

    @Test
    @WithMockUser(username = "a", roles = {"ADMIN"})
    void admin_adminRole_shouldPass() throws Exception {
        mockMvc.perform(get("/admin/panel"))
            .andExpect(status().isOk());
    }
}
